// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.List;
import java.util.stream.Collectors;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.query.QueryResults;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Differential tests for factorized tail aggregation over star joins: every query is evaluated once on the native LMDB
 * engine and once with the native engine disabled (the generic RDF4J evaluator), and the results must match. The
 * dataset is a star: hubs fan out over two predicates with different cardinalities, one hub has no matches on the
 * second branch (inner-join semantics must drop it), values include duplicates, and one triple lives in a named graph.
 */
public class LmdbNativeFactorizedTailAggregationTest {

	private static final String EX = "http://example.com/";
	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";

	@TempDir
	File dataDir;

	private SailRepository repository;

	@BeforeEach
	public void setUp() {
		repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc,ospc")));
		try (SailRepositoryConnection conn = repository.getConnection()) {
			ValueFactory vf = conn.getValueFactory();
			IRI p1 = vf.createIRI(EX, "p1");
			IRI p2 = vf.createIRI(EX, "p2");
			// hub1: 3 p1-branches, 2 p2-branches (one p2 value duplicated via a second hub)
			IRI hub1 = vf.createIRI(EX, "hub1");
			conn.add(hub1, p1, vf.createIRI(EX, "a1"));
			conn.add(hub1, p1, vf.createIRI(EX, "a2"));
			conn.add(hub1, p1, vf.createIRI(EX, "a3"));
			conn.add(hub1, p2, vf.createIRI(EX, "b1"));
			conn.add(hub1, p2, vf.createLiteral("shared"));
			// hub2: 1 p1-branch, 3 p2-branches (duplicate value "shared" across hubs)
			IRI hub2 = vf.createIRI(EX, "hub2");
			conn.add(hub2, p1, vf.createIRI(EX, "a1"));
			conn.add(hub2, p2, vf.createIRI(EX, "b2"));
			conn.add(hub2, p2, vf.createLiteral("shared"));
			conn.add(hub2, p2, vf.createLiteral("only2"));
			// hub3: p1-branches but NO p2 branch — must vanish from every joined aggregate
			IRI hub3 = vf.createIRI(EX, "hub3");
			conn.add(hub3, p1, vf.createIRI(EX, "a9"));
			// one p2 triple in a named graph (default-graph queries must still see it via the default dataset)
			conn.add(hub1, p2, vf.createIRI(EX, "bGraph"), vf.createIRI(EX, "g1"));
			// self-referencing triple for the repeated-variable gate
			conn.add(hub1, p1, hub1);
		}
	}

	@AfterEach
	public void tearDown() {
		repository.shutDown();
	}

	private List<String> rows(String query) {
		try (SailRepositoryConnection conn = repository.getConnection()) {
			List<BindingSet> result = QueryResults.asList(conn.prepareTupleQuery(query).evaluate());
			return result.stream().map(Object::toString).sorted().collect(Collectors.toList());
		}
	}

	private void assertSameAsGeneric(String query) {
		List<String> nativeRows = rows(query);
		String previous = System.getProperty(NATIVE_FLAG);
		List<String> genericRows;
		try {
			System.setProperty(NATIVE_FLAG, "false");
			genericRows = rows(query);
		} finally {
			if (previous == null) {
				System.clearProperty(NATIVE_FLAG);
			} else {
				System.setProperty(NATIVE_FLAG, previous);
			}
		}
		assertThat(nativeRows).as("native vs generic for:\n" + query).isEqualTo(genericRows);
	}

	private static String star(String select, String extra) {
		return "PREFIX ex: <" + EX + ">\n"
				+ "SELECT " + select + " WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ extra
				+ "}";
	}

	@Test
	public void countOverTailVariable() {
		assertSameAsGeneric(star("(COUNT(?b) AS ?c)", ""));
	}

	@Test
	public void countDistinctOverTailVariable() {
		assertSameAsGeneric(star("(COUNT(DISTINCT ?b) AS ?c)", ""));
	}

	@Test
	public void countOverHubMultipliesTailMatches() {
		assertSameAsGeneric(star("(COUNT(?s) AS ?c)", ""));
	}

	@Test
	public void countDistinctOverHubIgnoresTailMultiplicityButNotExistence() {
		// hub3 has no ex:p2 branch and must not be counted
		assertSameAsGeneric(star("(COUNT(DISTINCT ?s) AS ?c)", ""));
	}

	@Test
	public void countOverFirstBranchVariable() {
		assertSameAsGeneric(star("(COUNT(?a) AS ?c) (COUNT(DISTINCT ?a) AS ?d)", ""));
	}

	@Test
	public void mixedDistinctAndPlainCounts() {
		assertSameAsGeneric(star("(COUNT(?s) AS ?c) (COUNT(DISTINCT ?b) AS ?d) (COUNT(DISTINCT ?s) AS ?e)", ""));
	}

	@Test
	public void groupByHubWithCounts() {
		assertSameAsGeneric(star("?s (COUNT(?b) AS ?c) (COUNT(DISTINCT ?b) AS ?d)", "") + " GROUP BY ?s");
	}

	@Test
	public void groupByFirstBranchWithTailCounts() {
		assertSameAsGeneric(star("?a (COUNT(?b) AS ?c)", "") + " GROUP BY ?a");
	}

	@Test
	public void groupByTailVariable() {
		// group key produced by the tail pattern: handled by per-key sub-counting inside the batch loop
		assertSameAsGeneric(star("?b (COUNT(?s) AS ?c)", "") + " GROUP BY ?b");
	}

	@Test
	public void groupByTailVariableWithMixedAggregates() {
		assertSameAsGeneric(star("?b (COUNT(?s) AS ?c) (COUNT(DISTINCT ?s) AS ?d) (COUNT(?b) AS ?e)", "")
				+ " GROUP BY ?b");
	}

	@Test
	public void groupByTailContextVariable() {
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?g (COUNT(?s) AS ?c) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  GRAPH ?g { ?s ex:p2 ?b . }\n"
				+ "} GROUP BY ?g");
	}

	@Test
	public void groupByMixedPrefixAndTailFallsBack() {
		// two group slots, one from the tail: outside the sub-counting gate, must fall back correctly
		assertSameAsGeneric(star("?s ?b (COUNT(?a) AS ?c)", "") + " GROUP BY ?s ?b");
	}

	@Test
	public void filterOnTailVariableFallsBack() {
		assertSameAsGeneric(star("(COUNT(?s) AS ?c)", "  FILTER(?b != ex:b1)\n"));
	}

	@Test
	public void repeatedVariablePattern() {
		// ?s ex:p1 ?s is a repeated-variable pattern; must stay correct through the gate
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) WHERE { ?s ex:p2 ?b . ?s ex:p1 ?s . }");
	}

	@Test
	public void threeBranchStar() {
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) (COUNT(DISTINCT ?b) AS ?d) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p1 ?a2 .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "}");
	}

	@Test
	public void namedGraphTailPattern() {
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?b) AS ?c) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  GRAPH ?g { ?s ex:p2 ?b . }\n"
				+ "}");
	}

	@Test
	public void multiBranchStarWithMixedAggregates() {
		// three patterns: prefix drives ?s, the two trailing branches are independent given ?s and are
		// both consumed by aggregates — exercises the product-of-counts path with k=2 branches
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) (COUNT(?a2) AS ?d) (COUNT(DISTINCT ?a2) AS ?e)"
				+ " (COUNT(DISTINCT ?b) AS ?f) (COUNT(DISTINCT ?s) AS ?g) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p1 ?a2 .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "}");
	}

	@Test
	public void multiBranchStarGroupedByPrefix() {
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT ?s (COUNT(?a2) AS ?c) (COUNT(DISTINCT ?b) AS ?d) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p1 ?a2 .\n"
				+ "  ?s ex:p2 ?b .\n"
				+ "} GROUP BY ?s");
	}

	@Test
	public void chainedPatternsAreNotIndependentBranches() {
		// ?a p2 ?b reads ?a, which the p1 pattern produces: the branch-independence gate must keep the
		// chain on the correct path (single-branch tail over the last pattern)
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) (COUNT(DISTINCT ?b) AS ?d) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?a ex:p2 ?b .\n"
				+ "}");
	}

	@Test
	public void fullyBoundTailBecomesExistenceCheck() {
		// the tail shares every variable with the prefix, so per prefix row it is a pure existence
		// probe (the batch is one synthetic quad or empty)
		assertSameAsGeneric("PREFIX ex: <" + EX + ">\n"
				+ "SELECT (COUNT(?s) AS ?c) (COUNT(DISTINCT ?s) AS ?d) WHERE {\n"
				+ "  ?s ex:p1 ?a .\n"
				+ "  ?s ex:p2 ?a .\n"
				+ "}");
	}

	@Test
	public void plainStarCountDoesNotDependOnFactorizedTail() {
		assertSameAsGeneric(star("(COUNT(?b) AS ?c)", ""));
	}
}
